                  onToggleSelect(group.id);
                }
              }}
            >
              <div className="flex items-center gap-3">
                {selectMode && (
                  <Checkbox
                    checked={isSelected}
                    className="h-5 w-5 shrink-0 data-[state=checked]:bg-primary"
                    onClick={(e) => e.stopPropagation()}
