                  </DropdownMenu>
                )}
              </div>
              <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
                {children.map((child) => (
                  <ChinaTripCard
                    key={child.id}
                    trip={child}
                    selectMode={selectMode}
                    isSelected={selected.has(child.id)}
                    onToggleSelect={onToggleSelect}
                    onClick={() => {
                      if (selectMode) onToggleSelect(child.id);
