        description: `${result.done - result.failed} of ${result.total} images cached for offline.`,
      });
    } catch (err: any) {
      toast({ title: "Cache failed", description: err.message, variant: "destructive" });
    } finally {
      setBulkCaching(false);
      setBulkCacheProgress(null);
